<?phpdeclare(strict_types=1);/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/auth_check.php';$page_title='DataPersonilperBagian-POLRESSamosir';/Getpersonneldatafromdatabaseorganizedbysections$sectionsData=null;$error=null;try{$pdo=newPDO("mysql:host=".DB_HOST.";dbname=".DB_NAME.";unix_socket=".DB_SOCKET,DB_USER,DB_PASS)try{/Databaseoperations}catch(PDOException$e){error_log("Databaseerror:".$e->getMessage());thrownewException("Databaseoperationfailed");};$pdo->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);/Getallpersonnelwiththeirbagianinformation$stmt=$pdo->query("SELECTp.id,p.nama,p.nrp,p.status_ketasket,b.nama_bagianassection_name,pg.nama_pangkataspangkat,j.nama_jabatanasjabatan,ROW_NUMBER()OVER(PARTITIONBYb.nama_bagianORDERBYp.nama)asrow_numFROMpersonilpLEFTJOINbagianbONp.bagian_id=b.idLEFTJOINpangkatpgONp.pangkat_id=pg.idLEFTJOINjabatanjONp.jabatan_id=j.idWHEREp.is_deleted=0ANDp.is_active=1ORDERBYb.urutan,p.nama");$personnelData=$stmt->fetchAll(PDO::FETCH_ASSOC);/Grouppersonnelbysections$sections=[];forforeach($personnelDataas$person){$sectionName=$person['section_name']?:'TIDAKADABAGIAN';if(!isset($sections[$sectionName])){$sections[$sectionName]=['section_name'=>$sectionName,'row_number'=>count($sections)+1,'personnel_count'=>0,'personnel'=>[]];}$sections[$sectionName]['personnel'][]=['no'=>$person['row_num'],'nama'=>$person['nama'],'pangkat'=>$person['pangkat']?:'-','nrp'=>$person['nrp'],'jabatan'=>$person['jabatan']?:'-','ket'=>$person['ket']?:''];$sections[$sectionName]['personnel_count']++;}/Converttoindexedarray$sectionsData=['metadata'=>['source_file'=>'DatabaseMySQL','sheet_name'=>'PersonnelDatabase','total_sections'=>count($sections),'total_personnel'=>array_sum(array_column($sections,'personnel_count')),'created_at'=>date('Y-m-d\TH:i:s'),'description'=>'Personneldataorganizedbysectionsfromdatabase'],'sections'=>array_values($sections)];}catch(PDOException$e){$error="Databaseerror:".$e->getMessage();}catch(Exception$e){$error=$e->getMessage();}include__DIR__.'/../includes/components/header.php';?><divclass="containermt-4"><divclass="row"><divclass="col-12"><divclass="d-flexjustify-content-betweenalign-items-centermb-4"><div><h2><iclass="fasfa-usersme-2"></i>DataPersonilperBagian</h2><pclass="text-mutedmb-0">DatapersonilPOLRESSamosirberdasarkanstrukturorganisasi</p></div><divclass="d-flexgap-2"><buttonclass="btnbtn-outline-primary"onclick="expandAll()"><iclass="fasfa-expand-altme-1"></i>ExpandAll</button><buttonclass="btnbtn-outline-secondary"onclick="collapseAll()"><iclass="fasfa-compress-altme-1"></i>CollapseAll</button></div></div></div></div><?phpif($error):?><divclass="alertalert-danger"><iclass="fasfa-exclamation-triangleme-2"></i><strong>Error:</strong><?phpechohtmlspecialchars($error);?></div><?phpelseif($sectionsData):?><!--MetadataDisplay--><divclass="rowmb-4"><divclass="col-lg-8"><divclass="cardborder-primary"><divclass="card-headerbg-primarytext-white"><h5class="card-titlemb-0"><iclass="fasfa-info-circleme-2"></i>InformasiData</h5></div><divclass="card-body"><divclass="row"><divclass="col-md-6"><p><strong>SumberFile:</strong><?phpechohtmlspecialchars($sectionsData['metadata']['source_file']);?></p><p><strong>TotalBagian:</strong><?phpecho$sectionsData['metadata']['total_sections'];?>bagian</p></div><divclass="col-md-6"><p><strong>TotalPersonil:</strong><?phpecho$sectionsData['metadata']['total_personnel'];?>orang</p><p><strong>TanggalDibuat:</strong><?phpechodate('dFYH:i:s',strtotime($sectionsData['metadata']['created_at']));?></p></div></div><pclass="text-mutedmt-2"><?phpechohtmlspecialchars($sectionsData['metadata']['description']);?></p></div></div></div><divclass="col-lg-4"><divclass="cardborder-success"><divclass="card-headerbg-successtext-white"><h5class="card-titlemb-0"><iclass="fasfa-chart-barme-2"></i>Statistik</h5>